use std::collections::BTreeSet;

fn solve(s: String, order: Vec<i64>, k: i64) -> i64 {
    let n = s.len();
    let total = n * (n + 1) / 2;
    let mut invalid = total;
    let mut stars = BTreeSet::new();
    for t in 0..n {
        let i = order[t] as usize;
        stars.insert(i);
        let predecessor = stars.range(..i).rev().next().copied().unwrap_or(-1);
        let successor = stars.range(i..).next().copied().unwrap_or(n);
        let original_length = successor - predecessor - 1;
        let original_contribution = original_length * (original_length + 1) / 2;
        let left_length = i - predecessor - 1;
        let left_contribution = left_length * (left_length + 1) / 2;
        let right_length = successor - i - 1;
        let right_contribution = right_length * (right_length + 1) / 2;
        invalid = invalid - original_contribution + left_contribution + right_contribution;
        let valid = total - invalid;
        if valid >= k {
            return t as i64;
        }
    }
    -1
}
